#include<bits/stdc++.h>
using namespace std;
int fa[5000010],prufer[5000010];
int du[5000010],s[5000010];
int n,m;
int cnt,head[5000010],to[10000010],nxt[10000010];
void add(int u,int v)
{
	to[++cnt]=v;
	nxt[cnt]=head[u];
	head[u]=cnt;
}
int read()
{
    int x=0;
    char ch=getchar();
    while(!isdigit(ch))
    {
        ch=getchar();
    }
    while(isdigit(ch))
    {
        x=x*10+ch-'0';
        ch=getchar();
    }
    return x;
}
void encode()
{
    int tot=0;
    for(int i=1,j=1;i<=n-2;i++,j++)
    {
        while(du[j]!=1)
        {
            j++;
        }
        prufer[i]=fa[j];
        du[fa[j]]--;
        while(i<=n-2&&du[prufer[i]]==1&&prufer[i]<j)
        {
            prufer[i+1]=fa[prufer[i]];
            i++;
            du[prufer[i]]--;
        }
    }
}
void dfs(int x,int f=-1)
{
    fa[x]=f;
    for(int i=head[x];i;i=nxt[i])
    {
        int v=to[i];
        if(v!=f)
        {
            dfs(v,x);
        }
    }
}
void decode()
{
    prufer[n-1]=n;
    for(int i=1;i<=n-2;i++)
    {
        s[prufer[i]]++;
    }
    priority_queue<int,vector<int>,greater<int>> q;
    for(int i=1;i<=n;i++)
    {
        if(s[i]==0)
        {
            q.push(i);
        }
    }
    for(int i=1;i<=n-1;i++)
    {
        int t=q.top();
        q.pop();
        fa[t]=prufer[i];
        s[prufer[i]]--;
        if(s[prufer[i]]==0)
        {
            q.push(prufer[i]);
        }
    }
}
int main()
{
    n=read(),m=read();
    if(m==1)
    {
        for(int i=1;i<n;i++)
        {
            fa[i]=read();
            du[i]++;
            du[fa[i]]++;
            add(i,fa[i]);
            add(fa[i],i);
        }
        encode();
        long long ans=0;
        for(int i=1;i<=n-2;i++)
        {
            ans^=(1ll*i*prufer[i]);
        }
        printf("%lld",ans);
    }
    else
    {
        for(int i=1;i<=n-2;i++)
        {
            prufer[i]=read();
        }
        decode();
        long long ans=0;
        for(int i=1;i<n;i++)
        {
            ans^=(1ll*i*fa[i]);
        }
        printf("%lld",ans);
    }
    return 0;
}
